import { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import CreateRequest from './CreateRequest';

const STATUS_META = {
  pending:    { label: 'Pending',     cls: 'badge--pending' },
  inprogress: { label: 'In Progress', cls: 'badge--inprogress' },
  completed:  { label: 'Completed',   cls: 'badge--completed' },
  cancelled:  { label: 'Cancelled',   cls: 'badge--cancelled' },
};

const statusKey = (s = '') => s.toLowerCase().replace(/[\s_-]/g, '');

const NAV_ITEMS = [
  { id: 'dashboard', icon: '🏠', label: 'Dashboard' },
  { id: 'requests',  icon: '📋', label: 'My Requests' },
  { id: 'new',       icon: '➕', label: 'New Request' },
];

function RequestCard({ req, onDelete, onEdit }) {

  const meta =
    STATUS_META[statusKey(req.status)] ||
    STATUS_META.pending;

  return (

    <div className="request-card animate-fade-up">

      <div className="card-header">

        <h3 className="card-title">
          {req.title}
        </h3>

        <span className={`badge ${meta.cls}`}>
          {meta.label}
        </span>

      </div>

      {req.description && (
        <p className="card-description">
          {req.description}
        </p>
      )}

      <div className="card-meta">

        {req.category && (
          <div className="card-meta-item">
            <span>🏷️</span>
            <span className="card-category">
              {req.category}
            </span>
          </div>
        )}

        {req.address && (
          <div className="card-meta-item">
            <span>📍</span>
            <span>{req.address}</span>
          </div>
        )}

        {req.preferred_time && (
          <div className="card-meta-item">
            <span>🕐</span>
            <span>{req.preferred_time}</span>
          </div>
        )}

      </div>

      <div className="card-actions">

        <button
          className="btn btn--ghost btn--sm"
          onClick={() => onEdit(req)}
        >
          ✏️ Edit
        </button>

        <button
          className="btn btn--danger btn--sm"
          onClick={() => onDelete(req.id)}
        >
          🗑️ Delete
        </button>

      </div>

    </div>
  );
}

function Dashboard() {

  const navigate = useNavigate();

  const [requests, setRequests] = useState([]);

  const [activeNav, setActiveNav] =
    useState('dashboard');

  const [showCreate, setShowCreate] =
    useState(false);

  const [editReq, setEditReq] =
    useState(null);

  const [filter, setFilter] =
    useState('all');

  const user_id =
    localStorage.getItem('user_id');

  const fetchRequests = useCallback(async () => {

    const res = await axios.get(
      `http://127.0.0.1:5000/requests/${user_id}`
    );

    setRequests(res.data);

  }, [user_id]);

  useEffect(() => {

    fetchRequests();

    const interval = setInterval(() => {

      fetchRequests();

    }, 3000);

    return () => clearInterval(interval);

  }, [fetchRequests]);

  const deleteRequest = async (id) => {

    await axios.delete(
      `http://127.0.0.1:5000/delete-request/${id}`
    );

    fetchRequests();
  };

  const handleLogout = () => {

    localStorage.removeItem('user_id');

    navigate('/');
  };

  const stats = {

    total: requests.length,

    pending:
      requests.filter(
        r => statusKey(r.status) === 'pending'
      ).length,

    inprogress:
      requests.filter(
        r => statusKey(r.status) === 'inprogress'
      ).length,

    completed:
      requests.filter(
        r => statusKey(r.status) === 'completed'
      ).length,
  };

  const filtered =
    filter === 'all'
      ? requests
      : requests.filter(
          r => statusKey(r.status) === filter
        );

  const FILTERS = [

    {
      key: 'all',
      label: `All (${requests.length})`
    },

    {
      key: 'pending',
      label: `Pending (${stats.pending})`
    },

    {
      key: 'inprogress',
      label: `In Progress (${stats.inprogress})`
    },

    {
      key: 'completed',
      label: `Completed (${stats.completed})`
    },
  ];

  return (

    <div className="app-layout">

      <aside className="sidebar">

        <div className="sidebar-logo">

          <div className="sidebar-logo-icon">
            🏠
          </div>

          <span>ServeEase</span>

        </div>

        <nav className="sidebar-nav">

          {NAV_ITEMS.map(item => (

            <button
              key={item.id}
              className={`nav-item ${
                activeNav === item.id
                  ? 'active'
                  : ''
              }`}
              onClick={() => {

                setActiveNav(item.id);

                if (item.id === 'new') {

                  setShowCreate(true);

                  setActiveNav('requests');
                }
              }}
            >

              <span className="nav-item-icon">
                {item.icon}
              </span>

              {item.label}

            </button>
          ))}

        </nav>

        <div className="sidebar-footer">

          <button
            className="btn btn--ghost btn--full"
            onClick={handleLogout}
          >
            🚪 Sign Out
          </button>

        </div>

      </aside>

      <main className="main-content">

        <header className="topbar">

          <span className="topbar-title">
            Dashboard
          </span>

          <button
            className="btn btn--primary btn--sm"
            onClick={() => setShowCreate(true)}
          >
            ✨ New Request
          </button>

        </header>

        <div className="page-body">

          <div className="stats-grid">

            <div className="stat-card">
              <h3>{stats.total}</h3>
              <p>Total Requests</p>
            </div>

            <div className="stat-card">
              <h3>{stats.pending}</h3>
              <p>Pending</p>
            </div>

            <div className="stat-card">
              <h3>{stats.inprogress}</h3>
              <p>In Progress</p>
            </div>

            <div className="stat-card">
              <h3>{stats.completed}</h3>
              <p>Completed</p>
            </div>

          </div>

          <div className="chip-row">

            {FILTERS.map(f => (

              <button
                key={f.key}
                className={`chip ${
                  filter === f.key
                    ? 'active'
                    : ''
                }`}
                onClick={() => setFilter(f.key)}
              >

                {f.label}

              </button>
            ))}

          </div>

          <div className="requests-grid">

            {filtered.map(req => (

              <RequestCard
                key={req.id}
                req={req}
                onDelete={deleteRequest}
                onEdit={setEditReq}
              />
            ))}

          </div>

        </div>

      </main>

      {showCreate && (

        <div className="modal-overlay">

          <div className="modal">

            <CreateRequest
              refresh={fetchRequests}
              onClose={() => setShowCreate(false)}
            />

          </div>

        </div>
      )}

    </div>
  );
}

export default Dashboard;
